previewCss:
.darma-loader-skeleton-card {
  display: grid;
  gap: 10px;
  width: 148px;
  border-radius: 18px;
  padding: 14px;
  background: rgba(99, 102, 241, 0.08);
}
.darma-loader-skeleton-card b,
.darma-loader-skeleton-card i {
  display: block;
  border-radius: 12px;
  background: linear-gradient(90deg, rgba(99,102,241,.14), rgba(99,102,241,.34), rgba(99,102,241,.14));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-card-shimmer 1.15s linear infinite;
}
.darma-loader-skeleton-card b { height: 44px; }
.darma-loader-skeleton-card i { height: 10px; }
.darma-loader-skeleton-card i:last-child { width: 66%; }
@keyframes darma-loader-skeleton-card-shimmer { to { background-position: -220% 0; } }

